function doAdd(name,type,price,imgKey){var img=IMGS[imgKey]||"";var ex=_cart.find(function(i){return i.name===name&&i.type===type;});if(ex){ex.qty++;}else{_cart.push({name:name,type:type,price:price,img:img,qty:1});}var cc=document.getElementById("cart-count");if(cc)cc.textContent=_cart.reduce(function(a,i){return a+i.qty;},0);_showAddedPopup(name,price,img);}
function _showAddedPopup(name,price,imgSrc){var old=document.getElementById("bs-cart-popup");if(old)old.remove();var popup=document.createElement("div");popup.id="bs-cart-popup";popup.style.cssText="position:fixed;bottom:28px;right:28px;z-index:800;background:#050301;border:1px solid rgba(201,169,110,.25);padding:16px;width:300px;max-width:90vw;box-shadow:0 8px 40px rgba(0,0,0,.7);transform:translateY(20px);opacity:0;transition:transform .4s cubic-bezier(.25,.46,.45,.94),opacity .4s;";var imgEl=document.createElement("img");imgEl.src=imgSrc;imgEl.style.cssText="width:52px;height:60px;object-fit:cover;flex-shrink:0;border:1px solid rgba(201,169,110,.2)";var info=document.createElement("div");info.style.cssText="flex:1;min-width:0";var lbl=document.createElement("div");lbl.style.cssText="font-family:Cinzel,serif;font-size:.55rem;letter-spacing:.12em;color:#F4E8CC;margin-bottom:.25rem";lbl.textContent="Added to Cart";var nm=document.createElement("div");nm.style.cssText="font-family:Raleway,sans-serif;font-weight:200;font-size:.5rem;letter-spacing:.15em;color:rgba(201,169,110,.9);white-space:nowrap;overflow:hidden;text-overflow:ellipsis";nm.textContent=name;var pr=document.createElement("div");pr.style.cssText="font-family:Cinzel,serif;font-size:.6rem;color:var(--gold,#C9A96E);margin-top:.2rem";pr.textContent="₹"+price;info.appendChild(lbl);info.appendChild(nm);info.appendChild(pr);var closeBtn=document.createElement("button");closeBtn.style.cssText="background:none;border:none;color:rgba(201,169,110,.5);cursor:pointer;font-size:.9rem;padding:4px;flex-shrink:0;align-self:flex-start";closeBtn.innerHTML="&#x2715;";var top=document.createElement("div");top.style.cssText="display:flex;align-items:center;gap:14px";top.appendChild(imgEl);top.appendChild(info);top.appendChild(closeBtn);var contBtn=document.createElement("button");contBtn.style.cssText="flex:1;padding:9px;background:none;border:1px solid rgba(201,169,110,.3);color:rgba(201,169,110,.7);font-family:Raleway,sans-serif;font-weight:200;font-size:.46rem;letter-spacing:.25em;text-transform:uppercase;cursor:pointer";contBtn.textContent="Continue";var btns=document.createElement("div");btns.style.cssText="display:flex;gap:8px;margin-top:14px";btns.appendChild(contBtn);popup.appendChild(top);popup.appendChild(btns);document.body.appendChild(popup);function dismiss(){popup.style.transform="translateY(20px)";popup.style.opacity="0";setTimeout(function(){if(popup.parentNode)popup.remove();},400);}var timer=setTimeout(dismiss,4000);closeBtn.onclick=function(){clearTimeout(timer);dismiss();};contBtn.onclick=function(){clearTimeout(timer);dismiss();};requestAnimationFrame(function(){requestAnimationFrame(function(){popup.style.transform="translateY(0)";popup.style.opacity="1";});});}
document.addEventListener("DOMContentLoaded",function(){_si("pi-oud","oud_body");_si("pi-haw","haws_body");_si("pi-cr7","body");_si("pi-jag","body");_si("pi-lat","body");});

/* ═══ CURSOR — GPU transform, event-delegated ═══ */
(function(){
  var CD=document.getElementById('cd'), CR=document.getElementById('cr');
  if(!CD||!CR) return;
  var mx=innerWidth/2, my=innerHeight/2, rx=mx, ry=my, pending=false;
  /* Use transform:translate instead of left/top — compositor-only, no layout */
  CD.style.position='fixed'; CD.style.top='0'; CD.style.left='0';
  CR.style.position='fixed'; CR.style.top='0'; CR.style.left='0';
  CD.style.willChange='transform'; CR.style.willChange='transform';
  function render(){
    pending=false;
    CD.style.transform='translate('+mx+'px,'+my+'px) translate(-50%,-50%)';
    rx+=(mx-rx)*.13; ry+=(my-ry)*.13;
    CR.style.transform='translate('+(rx|0)+'px,'+(ry|0)+'px) translate(-50%,-50%)';
    if(Math.abs(mx-rx)>.5||Math.abs(my-ry)>.5) requestAnimationFrame(render);
    else pending=false;
  }
  document.addEventListener('mousemove',function(e){
    mx=e.clientX; my=e.clientY;
    if(!pending){ pending=true; requestAnimationFrame(render); }
  },{passive:true});
  /* Event delegation — no per-element listeners */
  document.addEventListener('mouseover',function(e){
    CR.classList.toggle('big',!!e.target.closest(
      'button,a,[onclick],.prod-card,.msk-tile,.soc-banner,.fchip,.qty-btn,.nav-icon'
    ));
  },{passive:true});
})();

/* ══ SPIRAL BACKGROUND ANIMATION ══ */
(function(){
  var canvas = document.getElementById('spiral-canvas');
  if(!canvas) return;
  var ctx = canvas.getContext('2d');
  if(!ctx) return;

  var dpr  = Math.max(1, 0.5 * (window.devicePixelRatio||1));
  var size = 0;
  var time = 0;
  var raf  = null;
  var startTs = null;
  var duration = 15000; /* 15s loop */

  /* Constants */
  var CAMERA_Z          = -400;
  var CAMERA_TRAVEL     = 3400;
  var START_DOT_Y       = 28;
  var VIEW_ZOOM         = 100;
  var N_STARS           = 5000;
  var TRAIL_LEN         = 80;
  var CHANGE_EVENT_TIME = 0.32;

  /* ── Maths helpers ── */
  function easePow(p, g) {
    if(p < 0.5) return 0.5 * Math.pow(2*p, g);
    return 1 - 0.5 * Math.pow(2*(1-p), g);
  }
  function easeOutElastic(x) {
    var c4 = (2*Math.PI)/4.5;
    if(x<=0) return 0; if(x>=1) return 1;
    return Math.pow(2,-8*x)*Math.sin((x*8-0.75)*c4)+1;
  }
  function lerp(a,b,t){ return a*(1-t)+b*t; }
  function clamp(v,mn,mx){ return Math.min(Math.max(v,mn),mx); }
  function mapRange(v,s1,e1,s2,e2){ return s2+(e2-s2)*((v-s1)/(e1-s1)); }

  /* ── Spiral path ── */
  function spiralPath(p) {
    p = clamp(1.2*p, 0, 1);
    p = easePow(p, 1.8);
    var turns = 6;
    var theta = 2*Math.PI*turns*Math.sqrt(p);
    var r = 170*Math.sqrt(p);
    return { x: r*Math.cos(theta), y: r*Math.sin(theta)+START_DOT_Y };
  }

  /* ── Stars ── */
  var stars = [];
  /* Seeded random for reproducibility */
  var seed = 1234;
  function seededRand() {
    seed = (seed*9301+49297)%233280;
    return seed/233280;
  }
  function randBetween(mn,mx,fn){ return mn+(fn()||Math.random())*(mx-mn); }

  function makeStar() {
    var angle = seededRand()*Math.PI*2;
    var distance = 30*seededRand()+15;
    var rotDir = seededRand()>0.5?1:-1;
    var expRate = 1.2+seededRand()*0.8;
    var finalScale = 0.7+seededRand()*0.6;
    var dx = distance*Math.cos(angle);
    var dy = distance*Math.sin(angle);
    var spiralLoc = (1-Math.pow(1-seededRand(),3.0))/1.3;
    var z = randBetween(0.5*CAMERA_Z, CAMERA_TRAVEL+CAMERA_Z, seededRand);
    z = lerp(z, CAMERA_TRAVEL/2, 0.3*spiralLoc);
    var swf = Math.pow(seededRand(), 2.0);
    return { angle:angle, distance:distance, rotDir:rotDir, expRate:expRate,
             finalScale:finalScale, dx:dx, dy:dy, spiralLoc:spiralLoc, z:z, swf:swf };
  }

  for(var i=0;i<N_STARS;i++) stars.push(makeStar());

  /* ── Project 3D → 2D ── */
  function showDot(pos, sizeFactor, t2) {
    var newCameraZ = CAMERA_Z + easePow(Math.pow(t2,1.2),1.8)*CAMERA_TRAVEL;
    if(pos.z > newCameraZ) {
      var depth = pos.z - newCameraZ;
      var x = VIEW_ZOOM*pos.x/depth;
      var y = VIEW_ZOOM*pos.y/depth;
      var sw = 400*sizeFactor/depth;
      ctx.lineWidth = sw;
      ctx.beginPath();
      ctx.arc(x, y, 0.5, 0, Math.PI*2);
      ctx.fill();
    }
  }

  /* ── Render star ── */
  function renderStar(star, p, t2) {
    var sp = spiralPath(star.spiralLoc);
    var q  = p - star.spiralLoc;
    if(q <= 0) return;

    var dp = clamp(4*q, 0, 1);
    var lin = dp, elas = easeOutElastic(dp), pow2 = Math.pow(dp,2);
    var easing;
    if(dp < 0.3) easing = lerp(lin, pow2, dp/0.3);
    else if(dp < 0.7) easing = lerp(pow2, elas, (dp-0.3)/0.4);
    else easing = elas;

    var sx, sy;
    if(dp < 0.3) {
      sx = lerp(sp.x, sp.x+star.dx*0.3, easing/0.3);
      sy = lerp(sp.y, sp.y+star.dy*0.3, easing/0.3);
    } else if(dp < 0.7) {
      var mp = (dp-0.3)/0.4;
      var cs = Math.sin(mp*Math.PI)*star.rotDir*1.5;
      var bx=sp.x+star.dx*0.3, by=sp.y+star.dy*0.3;
      var tx=sp.x+star.dx*0.7, ty=sp.y+star.dy*0.7;
      sx = lerp(bx,tx,mp) + (-star.dy*0.4*cs)*mp;
      sy = lerp(by,ty,mp) + (star.dx*0.4*cs)*mp;
    } else {
      var fp = (dp-0.7)/0.3;
      var bx2=sp.x+star.dx*0.7, by2=sp.y+star.dy*0.7;
      var td = star.distance*star.expRate*1.5;
      var sa = star.angle+1.2*star.rotDir*fp*Math.PI;
      sx = lerp(bx2, sp.x+td*Math.cos(sa), fp);
      sy = lerp(by2, sp.y+td*Math.sin(sa), fp);
    }

    var vx = (star.z-CAMERA_Z)*sx/VIEW_ZOOM;
    var vy = (star.z-CAMERA_Z)*sy/VIEW_ZOOM;

    var sm;
    if(dp < 0.6) sm = 1+dp*0.2;
    else { var tt=(dp-0.6)/0.4; sm=lerp(1.2, star.finalScale, tt); }

    showDot({x:vx, y:vy, z:star.z}, 8.5*star.swf*sm, t2);
  }

  /* ── Draw trail ── */
  function drawTrail(t1) {
    for(var i=0;i<TRAIL_LEN;i++) {
      var f = mapRange(i,0,TRAIL_LEN,1.1,0.1);
      var sw = (1.3*(1-t1)+3.0*Math.sin(Math.PI*t1))*f;
      ctx.fillStyle='white'; ctx.lineWidth=sw;
      var pt = t1-0.00015*i;
      var pos = spiralPath(pt);
      /* rotation wiggle */
      var ox=pos.x+5, oy=pos.y+5;
      var mx2=(pos.x+ox)/2, my2=(pos.y+oy)/2;
      var dx2=pos.x-mx2, dy2=pos.y-my2;
      var ang=Math.atan2(dy2,dx2);
      var rr=Math.sqrt(dx2*dx2+dy2*dy2);
      var o=(i%2===0)?-1:1;
      var ep=Math.sin(time*Math.PI*2)*0.5+0.5;
      var rx=mx2+rr*Math.cos(ang+o*Math.PI*easeOutElastic(ep));
      var ry=my2+rr*Math.sin(ang+o*Math.PI*easeOutElastic(ep));
      ctx.beginPath(); ctx.arc(rx,ry,sw/2,0,Math.PI*2); ctx.fill();
    }
  }

  /* ── Main render ── */
  function render(ts) {
    if(!startTs) startTs=ts;
    time = ((ts-startTs) % duration) / duration;

    var W = canvas.width/dpr, H = canvas.height/dpr;
    size = Math.max(W,H);

    /* Clear */
    ctx.fillStyle='black';
    ctx.fillRect(0,0,canvas.width/dpr,canvas.height/dpr);

    ctx.save();
    ctx.translate(W/2, H/2);

    var t1 = clamp(mapRange(time, 0, CHANGE_EVENT_TIME+0.25, 0, 1), 0, 1);
    var t2 = clamp(mapRange(time, CHANGE_EVENT_TIME, 1, 0, 1), 0, 1);

    ctx.rotate(-Math.PI*easePow(t2, 2.7));

    /* Trail */
    drawTrail(t1);

    /* Stars */
    ctx.fillStyle='white';
    for(var i=0;i<stars.length;i++) renderStar(stars[i], t1, t2);

    /* Start dot */
    if(time > CHANGE_EVENT_TIME) {
      var dy0 = CAMERA_Z*START_DOT_Y/VIEW_ZOOM;
      var newCZ = CAMERA_Z+easePow(Math.pow(t2,1.2),1.8)*CAMERA_TRAVEL;
      var depth0 = CAMERA_TRAVEL - newCZ;
      if(depth0>0){
        var px0=VIEW_ZOOM*0/depth0, py0=VIEW_ZOOM*dy0/depth0;
        var sw0=400*2.5/depth0;
        ctx.fillStyle='white'; ctx.lineWidth=sw0;
        ctx.beginPath(); ctx.arc(px0,py0,0.5,0,Math.PI*2); ctx.fill();
      }
    }
    ctx.restore();

    raf = requestAnimationFrame(render);
  }

  function resize() {
    dpr = Math.max(1, 0.5*(window.devicePixelRatio||1));
    canvas.width  = window.innerWidth  * dpr;
    canvas.height = window.innerHeight * dpr;
    ctx.scale(dpr, dpr);
    startTs = null; /* reset timer so animation restarts smoothly */
  }

  window.addEventListener('resize', resize, {passive:true});
  document.addEventListener('visibilitychange', function(){
    if(document.hidden){ if(raf){cancelAnimationFrame(raf);raf=null;} }
    else { startTs=null; raf=requestAnimationFrame(render); }
  });

  resize();
  raf = requestAnimationFrame(render);
})();
